    #[test]
    fn btrfs_write_create_and_write_inline() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("small.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();

        // Write small data (should use inline extent).
        let written = ops
            .write(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                0,
                b"Hello btrfs!",
            )
            .unwrap();
        assert_eq!(written, 12);

        // Read it back.
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .unwrap();
        assert_eq!(&data, b"Hello btrfs!");

        // Verify size updated.
        let updated = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(updated.size, 12);
    }

