    fn btrfs_readlink_caps_target_at_path_max() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let path_max = usize::try_from(LINUX_PATH_MAX).expect("LINUX_PATH_MAX fits usize");
        let long_target = format!("/{}", "x".repeat(path_max + 256));
        let attr = ops
            .symlink(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("long-link"),
                Path::new(&long_target),
                0,
                0,
            )
            .expect("create long symlink");

        let target = ops
            .readlink(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("readlink long symlink");
        assert_eq!(target.len(), path_max);
        assert_eq!(target, long_target.as_bytes()[..path_max]);
    }

    #[test]
    fn btrfs_write_hard_link() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        assert_eq!(attr.nlink, 1);

        let linked = ops
            .link(
                &cx,
                &mut RequestScope::empty(),
                attr.ino,
                InodeNumber(1),
                OsStr::new("hardlink.txt"),
            )
            .unwrap();
        assert_eq!(linked.ino, attr.ino);
        assert_eq!(linked.nlink, 2);

        // Both names should resolve to same inode.
        let a = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
            )
            .unwrap();
        let b = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("hardlink.txt"),
            )
            .unwrap();
        assert_eq!(a.ino, b.ino);
    }

