    #[test]
    fn btrfs_write_fallocate_unsupported_mode_bits_rejected() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("mode_bits.bin"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"keep-intact")
            .expect("seed file before mode-bit rejection");
        let before_attr = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr before rejection");
        let before_data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .expect("read before rejection");

        let err = ops
            .fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096, 0x40)
            .expect_err("unsupported mode bits should be rejected for btrfs");
        assert_eq!(err.to_errno(), libc::EOPNOTSUPP);
        assert!(
            matches!(err, FfsError::UnsupportedFeature(_)),
            "unexpected error: {err:?}"
        );
        let detail = err.to_string();
        assert!(
            detail.contains("unsupported mode bits"),
            "unexpected error detail for unsupported mode bits: {detail}"
        );
        let after_attr = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .expect("getattr after rejection");
        let after_data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .expect("read after rejection");
        assert_eq!(
            after_attr.size, before_attr.size,
            "unsupported mode bits must not change file size"
        );
        assert_eq!(
            after_data, before_data,
            "unsupported mode bits must not mutate file data"
        );
    }

    #[test]
    fn btrfs_write_fallocate_success_log_contract() {
        let _guard = fallocate_log_contract_guard();
        let buffer = SharedLogBuffer::default();
        let subscriber = tracing_subscriber::fmt()
            .json()
            .flatten_event(true)
            .with_current_span(true)
            .with_span_list(true)
            .with_env_filter(EnvFilter::new("info"))
            .with_writer(buffer.clone())
            .finish();

        // Use set_default (not with_default) so ALL threads use this subscriber,
        // not just the test thread. This prevents flaky failures where background
        // tasks log to a different subscriber.
        let default_guard = tracing::subscriber::set_default(subscriber);
        {
            let (fs, cx) = open_writable_btrfs();
            let ops: &dyn FsOps = &fs;

            let attr = ops
                .create(
                    &cx,
                    &mut RequestScope::empty(),
                    InodeNumber(1),
                    OsStr::new("log_success.bin"),
                    0o644,
                    0,
                    0,
                )
                .expect("create file for fallocate success log test");
            ops.fallocate(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096, 0)
                .expect("fallocate should succeed");
        }
        drop(default_guard);

        let logs = parse_json_logs(&buffer);
        let applied = logs
            .iter()
            .find(|entry| {
                entry.get("scenario_id").and_then(Value::as_str)
                    == Some("btrfs_rw_fallocate_prealloc")
                    && entry.get("outcome").and_then(Value::as_str) == Some("applied")
                    && entry
                        .get("operation_id")
                        .and_then(Value::as_str)
                        .is_some_and(|value| value.starts_with("btrfs-fallocate-"))
            })
            .unwrap_or_else(|| {
                let binding = buffer.inner.lock().unwrap();
                let raw = String::from_utf8_lossy(&binding);
                panic!("expected btrfs fallocate success log event: {logs:?}\nRAW BUFFER: {raw}");
            });

        assert_eq!(
            applied.get("scenario_id").and_then(Value::as_str),
            Some("btrfs_rw_fallocate_prealloc")
        );
        assert_eq!(
            applied.get("outcome").and_then(Value::as_str),
            Some("applied")
        );
        assert!(
            applied
                .get("operation_id")
                .and_then(Value::as_str)
                .is_some_and(|value| value.starts_with("btrfs-fallocate-")),
            "missing or malformed operation_id in success log: {applied:?}"
        );
    }

