    #[test]
    fn btrfs_write_flush_log_contract_records_non_durable_boundary() {
        let buffer = SharedLogBuffer::default();
        let subscriber = tracing_subscriber::fmt()
            .json()
            .flatten_event(true)
            .with_current_span(true)
            .with_span_list(true)
            .with_env_filter(EnvFilter::new("info"))
            .with_writer(buffer.clone())
            .finish();

        tracing::subscriber::with_default(subscriber, || {
            let (fs, cx) = open_writable_btrfs();
            let ops: &dyn FsOps = &fs;
            ops.flush(&cx, &mut RequestScope::empty(), InodeNumber(1), 5, 11)
                .expect("btrfs flush should succeed");
        });

        let logs = parse_json_logs(&buffer);
        let applied = logs
            .iter()
            .find(|entry| {
                entry.get("message").and_then(Value::as_str) == Some("btrfs_sync_applied")
                    && entry.get("scenario_id").and_then(Value::as_str) == Some("btrfs_rw_flush")
            })
            .expect("expected btrfs flush applied log");

        assert_eq!(
            applied.get("outcome").and_then(Value::as_str),
            Some("applied")
        );
        assert_eq!(
            applied.get("durability_boundary").and_then(Value::as_str),
            Some("none")
        );
        assert!(
            applied
                .get("operation_id")
                .and_then(Value::as_str)
                .is_some_and(|value| value.starts_with("btrfs-flush-")),
            "missing or malformed btrfs flush operation_id: {applied:?}"
        );
    }

    #[test]
    fn btrfs_write_unlink_purges_inode() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("doomed.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            0,
            b"data to purge",
        )
        .unwrap();
        ops.setxattr(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            "user.tag",
            b"val",
            XattrSetMode::Set,
        )
        .unwrap();

        // Unlink the file.
        ops.unlink(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("doomed.txt"),
        )
        .unwrap();

        // The inode should be gone — getattr should fail.
        let err = ops.getattr(&cx, &mut RequestScope::empty(), attr.ino);
        assert!(err.is_err(), "expected NotFound for purged inode");
    }

    #[test]
    fn btrfs_write_hard_link_unlink_preserves_data() {
        let (fs, cx) = open_writable_btrfs();
        let ops: &dyn FsOps = &fs;

        let attr = ops
            .create(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("original.txt"),
                0o644,
                0,
                0,
            )
            .unwrap();
        ops.write(&cx, &mut RequestScope::empty(), attr.ino, 0, b"shared data")
            .unwrap();

        // Create a hard link.
        ops.link(
            &cx,
            &mut RequestScope::empty(),
            attr.ino,
            InodeNumber(1),
            OsStr::new("link.txt"),
        )
        .unwrap();
        let link_attr = ops
            .lookup(
                &cx,
                &mut RequestScope::empty(),
                InodeNumber(1),
                OsStr::new("link.txt"),
            )
            .unwrap();
        assert_eq!(link_attr.nlink, 2);

        // Unlink the original — nlink goes to 1, inode should NOT be purged.
        ops.unlink(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("original.txt"),
        )
        .unwrap();

        // The inode should still be accessible via the link.
        let after = ops
            .getattr(&cx, &mut RequestScope::empty(), attr.ino)
            .unwrap();
        assert_eq!(after.nlink, 1);
        let data = ops
            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
            .unwrap();
        assert_eq!(data, b"shared data");

        // Unlink the last reference — now it should be purged.
        ops.unlink(
            &cx,
            &mut RequestScope::empty(),
            InodeNumber(1),
            OsStr::new("link.txt"),
        )
        .unwrap();
        assert!(
            ops.getattr(&cx, &mut RequestScope::empty(), attr.ino)
                .is_err()
        );
    }

